using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class WeeklyPlanConfiguration : IEntityTypeConfiguration<WeeklyPlan>{public void Configure(EntityTypeBuilder<WeeklyPlan> builder){builder.ToTable("weekly_plans");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("plan_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.NutritionTrack).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.OriginalMenuContent).HasColumnType("jsonb").IsRequired();builder.Property(e => e.CurrentMenuContent).HasColumnType("jsonb");builder.Property(e => e.GenerationSource).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.EstimatedTotalCostMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.EstimatedCostPerPersonMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.EstimatedCostGourmetBaselineMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.SavingsVsGourmetMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.SavingsVsGourmetPercent).HasColumnType("decimal(5,2)");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.Group).WithMany().HasForeignKey(e => e.GroupId);builder.HasOne(e => e.ParentPlan).WithMany().HasForeignKey(e => e.ParentPlanId);builder.HasOne(e => e.AiInteraction).WithMany().HasForeignKey(e => e.AiInteractionId);builder.HasOne(e => e.BudgetMode).WithMany().HasForeignKey(e => e.BudgetModeId);builder.HasIndex(e => new { e.UserId, e.StartDate });}}
